  ('real-estate-moex-02653', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '非住家用房屋，其為營業用者，該房屋稅之稅率，下列何者為正確？', '["最低不得少於其房屋現值百分之一點二，最高不得超過百分之二", "最低不得少於其房屋現值百分之一點五，最高不得超過百分之二點五", "最低不得少於其房屋現值百分之二，最高不得超過百分之三", "最低不得少於其房屋現值百分之三，最高不得超過百分之五"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
